module RefModule(
	input 	clk,
	input 	rst,
	input 	enable,
	input 	[7:0] input_data,
	output reg [255:0] output_data
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt)
begin
	if (rst)
		output_data <= 256'b0;
	else if (enable)
		output_data <= 1 << input_data;
	else
		output_data <= 256'b0;
end

endmodule
